import{_ as o,o as a,c as l,ag as t}from"./chunks/framework.DAY4Zhxq.js";const g=JSON.parse('{"title":"Model Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/models.md","filePath":"guide/models.md"}'),i={name:"guide/models.md"};function r(s,e,d,n,c,m){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="model-management" tabindex="-1">Model Management <a class="header-anchor" href="#model-management" aria-label="Permalink to &quot;Model Management&quot;">​</a></h1><h2 id="browsing-local-models" tabindex="-1">Browsing Local Models <a class="header-anchor" href="#browsing-local-models" aria-label="Permalink to &quot;Browsing Local Models&quot;">​</a></h2><p>The <strong>Models → Local</strong> tab lists all models you have pulled. For each model you can see:</p><ul><li>Parameter count, quantization, and file size</li><li>GPU/VRAM requirements (detected from your hardware via <code>detect_hardware</code>)</li><li>Custom tags and favorite status</li></ul><p>Click a model to open its detail panel, where you can view the full Ollama model card, available tags, and edit per-model generation defaults.</p><h2 id="pulling-models" tabindex="-1">Pulling Models <a class="header-anchor" href="#pulling-models" aria-label="Permalink to &quot;Pulling Models&quot;">​</a></h2><ol><li>Go to <strong>Models → Library</strong> and search for a model name.</li><li>Click a model to see available tags (e.g. <code>7b</code>, <code>13b</code>, <code>instruct</code>, <code>q4_K_M</code>).</li><li>Click <strong>Pull</strong> to start downloading. Progress is shown in real time.</li><li>The model appears in the Local tab once complete.</li></ol><p>You can also pull directly by name: open a conversation, type the model name into the model selector, and Alpaka Desktop will prompt you to pull it.</p><h2 id="deleting-models" tabindex="-1">Deleting Models <a class="header-anchor" href="#deleting-models" aria-label="Permalink to &quot;Deleting Models&quot;">​</a></h2><p>In <strong>Models → Local</strong>, click the three-dot menu on any model → <strong>Delete</strong>. The model is removed from disk via <code>ollama rm</code>.</p><h2 id="tags-and-favorites" tabindex="-1">Tags and Favorites <a class="header-anchor" href="#tags-and-favorites" aria-label="Permalink to &quot;Tags and Favorites&quot;">​</a></h2><ul><li><strong>Favorite</strong> a model (⭐) to float it to the top of the model selector.</li><li><strong>Tags</strong> are custom text labels you apply to models (e.g. <code>coding</code>, <code>fast</code>, <code>vision</code>).</li><li>Filter the local model list and the chat model selector by tag.</li></ul><h2 id="custom-model-creation-modelfile" tabindex="-1">Custom Model Creation (Modelfile) <a class="header-anchor" href="#custom-model-creation-modelfile" aria-label="Permalink to &quot;Custom Model Creation (Modelfile)&quot;">​</a></h2><p>Alpaka Desktop includes a full Modelfile editor (CodeMirror) for creating custom Ollama models:</p><ol><li>Go to <strong>Models → Create</strong>.</li><li>Write your Modelfile (see the <a href="https://github.com/ollama/ollama/blob/main/docs/modelfile.md" target="_blank" rel="noreferrer">Ollama Modelfile reference</a>).</li><li>Click <strong>Create</strong>. Progress streams in real time; you can cancel mid-stream.</li><li>A desktop notification confirms when the model is ready.</li></ol><h2 id="storage-path" tabindex="-1">Storage Path <a class="header-anchor" href="#storage-path" aria-label="Permalink to &quot;Storage Path&quot;">​</a></h2><p>By default, Ollama stores model blobs in <code>~/.ollama/models</code>. To change this:</p><ol><li>Go to <strong>Settings → Engine → Model Storage Path</strong>.</li><li>Enter the new absolute path.</li><li>Click <strong>Save</strong>. Alpaka Desktop writes a systemd service override (<code>OLLAMA_MODELS</code>) and restarts the Ollama service automatically.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Changing the storage path does not move existing models. You must manually move the <code>~/.ollama/models/</code> directory contents to the new path before saving, or re-pull models after the change.</p></div>',19)])])}const u=o(i,[["render",r]]);export{g as __pageData,u as default};
